import{c as e,Q as t,j as a,m as r}from"./chunks/framework.j5cTrcw1.js";const g=JSON.parse('{"title":"常见问题 (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),d={name:"faq.md"};function c(l,o,s,n,i,q){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="常见问题-faq" tabindex="-1">常见问题 (FAQ) <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题 (FAQ)&quot;">​</a></h1><h3 id="q1-安装脚本提示-docker-command-not-found" tabindex="-1">Q1: 安装脚本提示 &quot;Docker command not found&quot;？ <a class="header-anchor" href="#q1-安装脚本提示-docker-command-not-found" aria-label="Permalink to &quot;Q1: 安装脚本提示 &quot;Docker command not found&quot;？&quot;">​</a></h3><p><strong>A</strong>: 请确保您的系统已安装 Docker 和 Docker Compose。</p><ul><li>Ubuntu/Debian 安装 Docker: <code>curl -fsSL https://get.docker.com | bash</code></li></ul><h3 id="q2-面板无法访问-connection-refused" tabindex="-1">Q2: 面板无法访问 (Connection Refused)？ <a class="header-anchor" href="#q2-面板无法访问-connection-refused" aria-label="Permalink to &quot;Q2: 面板无法访问 (Connection Refused)？&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>检查防火墙是否放行了前端端口（默认 <code>6366</code>）。</li><li>检查容器是否正常运行: <code>docker ps</code>。</li><li>查看容器日志: <code>docker logs flvx-svcackend</code> 或 <code>docker logs flvx-svc-frontend</code>。</li></ol><h3 id="q3-节点显示离线" tabindex="-1">Q3: 节点显示离线？ <a class="header-anchor" href="#q3-节点显示离线" aria-label="Permalink to &quot;Q3: 节点显示离线？&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>检查节点服务器与面板服务器之间的网络连通性。</li><li>确认在节点端安装时输入的 <strong>面板地址</strong> 和 <strong>密钥</strong> 是否正确。</li><li>检查节点端服务状态: <code>systemctl status flvx_agent</code>（旧版为 <code>flux_agent</code>）。</li><li>查看节点端日志: <code>journalctl -u flvx_agent -f</code>（旧版为 <code>flux_agent</code>）。</li></ol><h3 id="q4-只有-tcp-能通-udp-不通" tabindex="-1">Q4: 只有 TCP 能通，UDP 不通？ <a class="header-anchor" href="#q4-只有-tcp-能通-udp-不通" aria-label="Permalink to &quot;Q4: 只有 TCP 能通，UDP 不通？&quot;">​</a></h3><p><strong>A</strong>: 请检查服务器防火墙和安全组（AWS/阿里云/腾讯云等）是否同时放行了对应端口的 <strong>TCP 和 UDP</strong> 协议。</p><h3 id="q5-ipv6-无法使用" tabindex="-1">Q5: IPv6 无法使用？ <a class="header-anchor" href="#q5-ipv6-无法使用" aria-label="Permalink to &quot;Q5: IPv6 无法使用？&quot;">​</a></h3><p><strong>A</strong>: 面板安装脚本会自动尝试配置 Docker 的 IPv6。如果失败，请手动检查 <code>/etc/docker/daemon.json</code> 配置，确保 <code>ipv6: true</code> 且分配了正确的 <code>fixed-cidr-v6</code> 子网。</p><h3 id="q6-如何切换到-postgresql" tabindex="-1">Q6: 如何切换到 PostgreSQL？ <a class="header-anchor" href="#q6-如何切换到-postgresql" aria-label="Permalink to &quot;Q6: 如何切换到 PostgreSQL？&quot;">​</a></h3><p><strong>A</strong>: 在 <code>.env</code> 文件中设置 <code>DB_TYPE=postgres</code>，并让 <code>DATABASE_URL</code> 与 <code>POSTGRES_*</code> 保持一致，然后执行 <code>docker compose up -d</code> 重启服务即可。使用安装脚本部署时，<code>POSTGRES_PASSWORD</code> 会自动随机生成并写入 <code>.env</code>。详见 <a href="./postgresql.html">PostgreSQL 数据库指南</a>。</p><h3 id="q7-从-sqlite-迁移到-postgresql-后数据丢失" tabindex="-1">Q7: 从 SQLite 迁移到 PostgreSQL 后数据丢失？ <a class="header-anchor" href="#q7-从-sqlite-迁移到-postgresql-后数据丢失" aria-label="Permalink to &quot;Q7: 从 SQLite 迁移到 PostgreSQL 后数据丢失？&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>确认迁移前已备份 SQLite 文件（<code>gost.db.bak</code>）。</li><li>确认 <code>pgloader</code> 命令执行成功，检查其输出是否有报错。</li><li>确认 <code>.env</code> 中 <code>DATABASE_URL</code> 的密码与 <code>POSTGRES_PASSWORD</code> 一致。</li><li>详细迁移步骤参考 <a href="./postgresql.html">PostgreSQL 数据库指南 - 从 SQLite 迁移</a>。</li></ol><h3 id="q8-postgresql-容器启动失败" tabindex="-1">Q8: PostgreSQL 容器启动失败？ <a class="header-anchor" href="#q8-postgresql-容器启动失败" aria-label="Permalink to &quot;Q8: PostgreSQL 容器启动失败？&quot;">​</a></h3><p><strong>A</strong>:</p><ol><li>检查 <code>POSTGRES_PASSWORD</code> 是否已设置（不能为空）。</li><li>查看容器日志：<code>docker logs flvx-svcostgres</code>。</li><li>如果是首次启动后修改了密码，需要删除旧的数据卷重新初始化：<code>docker volume rm postgres_data</code>。</li></ol>',22)])])}const p=e(d,[["render",c]]);export{g as __pageData,p as default};
